    state = {
        element,
        dotNetRef,
        timeoutMs,
        isIdle: false,
        timerId: null,
        events,
        handler: resetTimer,
    };

    for (const evt of events) {
        element.addEventListener(evt, resetTimer, { passive: true });
    }

    // Start the initial idle countdown
    state.timerId = setTimeout(() => {
        state.isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);
